CustomField.formula:
IF( ISBLANK( ContactId ) = true,
IF(TEXT(Lead.Salutation) = "Mr.","Sehr geehrter Herr " & Lead.LastName, IF(Text(Lead.Salutation) = "Ms.","Sehr geehrte Frau " & Lead.LastName, "Sehr geehrte/r Frau/Herr " & Lead.LastName)) , IF(TEXT(Contact.Salutation) = "Mr.","Sehr geehrter Herr " & Contact.LastName, IF(Text(Contact.Salutation) = "Ms.","Sehr geehrte Frau " & Contact.LastName, "Sehr geehrte/r Frau/Herr " & Contact.LastName))
)
